#include <zephyr/sys/util.h>

#include "satellites.h"

/*
 * The sats[] table (with its length baked in) is generated by
 * tools/orbital_params_fetch.py. CMake points SAT_PARAMS_FILE at the generated
 * table (src/sat_params.generated.c, gitignored) when present, else the
 * committed all-zero placeholder (src/sat_params.c). It is included here — not
 * built as a separate CMake source — so sats_count can be derived with
 * ARRAY_SIZE in the same translation unit; the generator emits no count.
 */
#ifndef SAT_PARAMS_FILE
#define SAT_PARAMS_FILE "sat_params.c"
#endif
#include SAT_PARAMS_FILE

const size_t sats_count = ARRAY_SIZE(sats);
